"""
Backboard LLM Analysis service for scam detection.
Implements RAG with Backboard.io for document-based scam pattern matching.

Features:
- Initialize assistant with scam knowledge base
- Upload and index scam pattern documents
- Query assistant about detected scams
"""

import asyncio
import time
import logging
from typing import Dict, Optional
import httpx

logger = logging.getLogger(__name__)

from config import BACKBOARD_API_KEY


class BackboardScamAnalyzer:
    """
    Handles scam detection using Backboard.io RAG system.
    
    Workflow:
    1. Initialize: Create assistant and upload scam pattern documents
    2. Index: Wait for documents to be indexed
    3. Query: Ask assistant about transcript for scam patterns
    
    MOCK MODE: All API calls are currently DISABLED (mock mode enabled)
    To enable real API calls, modify the initialize() method
    """
    
    def __init__(self, api_key: str = BACKBOARD_API_KEY):
        """Initialize Backboard client."""
        if not api_key:
            raise ValueError("BACKBOARD_API_KEY not configured")
        
        self.api_key = api_key
        self.base_url = "https://app.backboard.io/api"
        self.assistant_id = None
        self.documents = []
        self.initialized = False
        self.current_thread_id = None  # Track current thread
        self.current_thread_id = None
        
    async def initialize(self) -> bool:
        """
        Initialize the analyzer using an existing assistant.
        This should be called once during app startup.
        
        Returns:
            bool: True if initialization successful, False otherwise
        """
        try:
            logger.info("Initializing Backboard Scam Analyzer...")
            
            # Use existing assistant that already has indexed data
            self.assistant_id = "298103cb-635f-4b66-b2b2-6fea1e4729b4"
            logger.info(f"✅ Using existing Assistant ID: {self.assistant_id}")
            logger.info("✅ Assistant has pre-indexed scam pattern data")
            
            self.initialized = True
            logger.info("🚀 Backboard Scam Analyzer initialized successfully!")
            logger.info("   Ready to create threads and analyze conversations")
            return True
            
        except Exception as e:
            logger.error(f"Initialization error: {str(e)}")
            return False
    
    async def _create_assistant(self) -> Optional[str]:
        """Create a new Backboard assistant for scam detection."""
        try:
            headers = {
                "X-API-Key": self.api_key,
                "Content-Type": "application/json"
            }
            
            payload = {
                "name": "Elephant Information Giver",
                "system_prompt": (
                    "stick to the document and do not hallucinate while answering"
                    )
            }
            
            async with httpx.AsyncClient(timeout=30.0) as client:
                response = await client.post(
                    f"{self.base_url}/assistants",
                    headers=headers,
                    json=payload
                )
                logger.info(response.text)
            
            if response.status_code == 200:
                result = response.json()
                return result.get("id") or result.get("assistant_id")
            else:
                logger.error(f"Create assistant failed: {response.status_code} {response.text}")
                return None
                
        except Exception as e:
            logger.error(f"Create assistant error: {str(e)}")
            return None
    
    async def _upload_scam_documents(self) -> bool:
        """
        Upload scam pattern documents to the assistant.
        For now, we'll create documents from scam patterns database.
        
        In production, these could be:
        - PDFs with known scam scripts
        - Text files with scam indicators
        - Curated scam case studies
        """
        try:
            scam_patterns = self._get_scam_patterns_content()
            
            if not scam_patterns:
                logger.error("No scam patterns to upload")
                return False
            
            headers = {
                "X-API-Key": self.api_key,
                # Don't set Content-Type, httpx will set it to multipart/form-data
            }
            
            # Upload each document
            for doc_name, doc_content in scam_patterns.items():
                try:
                    # Prepare multipart form data with file parameter
                    files = {
                        "file": (doc_name, doc_content, "text/plain")
                    }
                    
                    async with httpx.AsyncClient(timeout=30.0) as client:
                        response = await client.post(
                            f"{self.base_url}/assistants/{self.assistant_id}/documents",
                            headers=headers,
                            files=files  # ✅ Use files parameter for multipart/form-data
                        )
                    
                    if response.status_code in [200]:
                        doc_data = response.json()
                        doc_id = doc_data.get("id") or doc_data.get("document_id")
                        self.documents.append({
                            "id": doc_id,
                            "name": doc_name,
                            "status": "processing"
                        })
                        logger.info(f"✅ Uploaded: {doc_name}")
                    else:
                        logger.error(f"Upload failed for {doc_name}: {response.status_code} {response.text}")
                        return False
                        
                except Exception as e:
                    logger.error(f"Error uploading {doc_name}: {str(e)}")
                    return False
            
            return True
            
        except Exception as e:
            logger.error(f"Upload documents error: {str(e)}")
            return False
    
    async def _wait_for_indexing(self, max_wait_seconds: int = 300) -> bool:
        """
        Wait for all documents to be indexed before proceeding.
        Polls document status every 2 seconds.
        
        Args:
            max_wait_seconds: Maximum time to wait for indexing
            
        Returns:
            bool: True if all documents indexed, False if timeout/error
        """
        try:
            logger.info("⏳ Waiting for documents to be indexed...")
            start_time = time.time()
            
            while True:
                elapsed = time.time() - start_time
                
                # Check timeout
                if elapsed > max_wait_seconds:
                    logger.error(f"Indexing timeout after {max_wait_seconds} seconds")
                    return False
                
                # Check status of all documents
                all_indexed = True
                headers = {
                    "X-API-Key": self.api_key,
                    "Content-Type": "application/json"
                }
                
                for doc in self.documents:
                    async with httpx.AsyncClient(timeout=30.0) as client:
                        response = await client.get(
                            f"{self.base_url}/assistants/{self.assistant_id}/documents/{doc['id']}",
                            headers=headers
                        )
                    
                    if response.status_code == 200:
                        doc_data = response.json()
                        status = doc_data.get("status", "processing")
                        doc["status"] = status
                        
                        if status == "indexed":
                            logger.info(f"   ✅ {doc['name']}: indexed")
                        elif status == "failed":
                            logger.error(f"   ❌ {doc['name']}: indexing failed")
                            return False
                        else:
                            logger.info(f"   ⏳ {doc['name']}: {status}... ({elapsed:.0f}s elapsed)")
                            all_indexed = False
                    else:
                        logger.error(f"Status check failed: {response.status_code}")
                        all_indexed = False
                
                # If all indexed, we're done
                if all_indexed:
                    logger.info("✅ All documents indexed!")
                    return True
                
                # Wait before next check
                await asyncio.sleep(2)
                
        except Exception as e:
            logger.error(f"Indexing wait error: {str(e)}")
            return False
    
    async def _create_thread(self) -> Optional[str]:
        """Create a thread for the conversation."""
        try:
            headers = {
                "X-API-Key": self.api_key,
            }
            
            async with httpx.AsyncClient(timeout=30.0) as client:
                response = await client.post(
                    f"{self.base_url}/assistants/{self.assistant_id}/threads",
                    headers=headers,
                    json={}
                )
            
            if response.status_code == 200:
                result = response.json()
                return result.get("id") or result.get("thread_id")
            else:
                logger.error(f"Create thread failed: {response.status_code} {response.text}")
                return None
                
        except Exception as e:
            logger.error(f"Create thread error: {str(e)}")
            return None
    
    async def create_thread_for_chunk(self) -> Optional[str]:
        """
        Create a new thread for each conversation.
        All chunks from the same conversation use the same thread.
        When a new conversation starts, call this to create a new thread.
        
        Returns:
            Thread ID or None if failed
        """
        if not self.initialized:
            logger.error("Analyzer not initialized. Call initialize() first.")
            return None
        
        try:
            thread_id = await self._create_thread()
            if thread_id:
                self.current_thread_id = thread_id  # Always update current thread
                logger.info(f"✅ New conversation thread created: {thread_id}")
            else:
                logger.error("Failed to create thread for conversation")
            return thread_id
        except Exception as e:
            logger.error(f"Error creating thread for conversation: {str(e)}")
            return None
    
    def get_current_thread(self) -> Optional[str]:
        """Get the current thread ID for ongoing conversation."""
        return self.current_thread_id
    
    async def send_message_to_thread(self, thread_id: str, message: str) -> Optional[str]:
        """
        Send a message (chunk) to the thread and get response from assistant.
        Multiple chunks should use the same thread_id to maintain context.
        
        Args:
            thread_id: The thread ID created by create_thread_for_chunk()
            message: The transcript chunk to analyze
            
        Returns:
            Assistant's response or None if failed
        """
        if not self.initialized:
            logger.error("Analyzer not initialized")
            return None
        
        if not thread_id:
            logger.error("No thread ID provided")
            return None
        
        try:
            headers = {
                "X-API-Key": self.api_key,
            }
            
            # Send message to thread
            payload = {
                "content": message,
                "stream": "false",
                "memory": "Auto"
            }
            
            async with httpx.AsyncClient(timeout=30.0) as client:
                response = await client.post(
                    f"{self.base_url}/threads/{thread_id}/messages",
                    headers=headers,
                    data=payload
                )
            
            if response.status_code not in [200, 201]:
                logger.error(f"Failed to add message to thread: {response.status_code} {response.text}")
                return None
            
            logger.info(f"✅ Message added to thread {thread_id}")
            result = response.json()
            
            # Get the response directly from the result
            if "message" in result:
                return result.get("message")
            elif "content" in result:
                return result.get("content")
            else:
                return response.text
            
        except Exception as e:
            logger.error(f"Error sending message to thread: {str(e)}")
            return None
    
    async def _get_assistant_response(self, thread_id: str, run_id: str, max_wait: int = 60) -> Optional[str]:
        """
        Wait for assistant response and retrieve it.
        
        Args:
            thread_id: The thread ID
            run_id: The run ID
            max_wait: Maximum seconds to wait for response
            
        Returns:
            Assistant's response text or None
        """
        try:
            headers = {
                "X-API-Key": self.api_key,
                "Content-Type": "application/json"
            }
            
            start_time = time.time()
            
            while True:
                elapsed = time.time() - start_time
                
                if elapsed > max_wait:
                    logger.error(f"Timeout waiting for assistant response after {max_wait}s")
                    return None
                
                # Check run status
                async with httpx.AsyncClient(timeout=30.0) as client:
                    response = await client.get(
                        f"{self.base_url}/threads/{thread_id}/runs/{run_id}",
                        headers=headers
                    )
                
                if response.status_code == 200:
                    run_data = response.json()
                    status = run_data.get("status")
                    
                    if status == "completed":
                        logger.info("✅ Assistant response ready")
                        break
                    elif status == "failed":
                        logger.error(f"Assistant run failed: {run_data.get('last_error')}")
                        return None
                    elif status == "running":
                        logger.info(f"⏳ Waiting for response... ({elapsed:.1f}s)")
                        await asyncio.sleep(1)
                    else:
                        logger.info(f"Run status: {status}")
                        await asyncio.sleep(1)
                else:
                    logger.error(f"Failed to get run status: {response.status_code}")
                    await asyncio.sleep(1)
            
            # Get messages from the thread
            async with httpx.AsyncClient(timeout=30.0) as client:
                response = await client.get(
                    f"{self.base_url}/threads/{thread_id}/messages",
                    headers=headers
                )
            
            if response.status_code == 200:
                messages_data = response.json()
                messages = messages_data.get("data", [])
                
                # Get the latest assistant message
                for msg in messages:
                    if msg.get("role") == "assistant":
                        content = msg.get("content", [])
                        if content:
                            return content[0].get("text", {}).get("value")
            
            return None
            
        except Exception as e:
            logger.error(f"Error getting assistant response: {str(e)}")
            return None
    
